    {
      "path": "package.json",
      "content": "{
  "name": "project-management-api",
  "version": "1.0.0",
  "main": "src/app.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.17.1",
    "crypto": "^1.0.0",
    "supertest": "^6.0.0"
  }
}"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const app = express();
const crypto = require('crypto');
require('./lib/errors')();

// Middleware to parse JSON bodies
app.use(express.json());

// Routes
app.use('/projects', require('./modules/projects/routes'));
app.use('/projects/:projectId/members', require('./modules/members/routes'));
app.use('/projects/:projectId/tasks', require('./modules/tasks/routes'));
app.use('/projects/:projectId/tasks/:taskId/comments', require('./modules/comments/routes'));

// Start the server
module.exports = app;
"
    },
    {
      "path": "src/lib/errors.js",
      "content": "const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};
exports.sendError = sendError;
"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');

// Create a new project
router.post('/', async (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'MissingName', 'Project name is required');
  const project = await service.createProject({ id: crypto.randomUUID(), ...req.body });
  res.status(201).json({ project });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const projects = [];
exports.createProject = ({ id, name }) => {
  const project = { id, name };
  projects.push(project);
  return project;
};
"
    },
    {
      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');

// Create a new member
router.post('/', async (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'InvalidMemberData', 'User ID and role are required');
  const member = await service.createMember({ userId: req.body.userId, role: req.body.role, projectId: req.params.projectId });
  res.status(201).json({ member });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/members/service.js",
      "content": "const members = [];
exports.createMember = ({ userId, role, projectId }) => {
  const member = { id: crypto.randomUUID(), userId, role };
  members.push(member);
  return member;
};
"
    },
    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');

// Create a new task
router.post('/', async (req, res) => {
  const task = await service.createTask({ status: 'todo', projectId: req.params.projectId });
  res.status(201).json({ task });
});

// Update a task status
router.patch('/:taskId', async (req, res) => {
  const allowedStatuses = ['todo', 'done'];
  if (!allowedStatuses.includes(req.body.status)) return sendError(res, 400, 'InvalidStatus', 'Task status must be one of todo or done');
  const task = await service.updateTaskStatus({ taskId: req.params.taskId, newStatus: req.body.status });
  res.json({ task });
});

// Filter tasks by status
router.get('/', async (req, res) => {
  const tasks = await service.getTasksByStatus(req.query.status || 'todo');
  res.json({ tasks });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const tasks = [];
exports.createTask = ({ status, projectId }) => {
  const task = { id: crypto.randomUUID(), status };
  tasks.push(task);
  return task;
};

exports.updateTaskStatus = ({ taskId, newStatus }) => {
  const taskIndex = tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) throw new Error('NotFound');
  tasks[taskIndex].status = newStatus;
  return tasks[taskIndex];
};

exports.getTasksByStatus = status => {
  return tasks.filter(t => t.status === status);
};
"
    },
    {
      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');

// Create a new comment
router.post('/', async (req, res) => {
  if (!req.body.message) return sendError(res, 400, 'MissingMessage', 'Comment message is required');
  const comment = await service.createComment({ message: req.body.message, taskId: req.params.taskId });
  res.status(201).json({ comment });
});

// Get comments for a task
router.get('/', async (req, res) => {
  const comments = await service.getCommentsForTask(req.params.taskId);
  res.json({ comments });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/comments/service.js",
      "content": "const comments = [];
exports.createComment = ({ message, taskId }) => {
  const comment = { id: crypto.randomUUID(), message };
  comments.push(comment);
  return comment;
};

exports.getCommentsForTask = taskId => {
  return comments.filter(c => c.taskId === taskId);
};
"
    }
  ],
  "notes": "Added supertest dependency for testing purposes, and included necessary changes to package.json, app.js, and the modules' routes and services."
}
